"""
MKT Context Commentary — Jeremiah 4–6 (92 verses)
Run: python3 scripts/zc-context-jeremiah-4-6.py

Key decisions:
- The "Foe from the North" (4:6; 6:1,22): left ambiguous historically (Scythians
  ca. 627-620 BCE are one candidate per Herodotus; Babylon after 605 BCE is the
  dominant retrospective identification). Treat the ambiguity as theologically
  deliberate — focus is on the theological meaning, not the historical identification.
- 4:23-28 cosmic-undoing vision: highlight the tohu-vavohu (Gen 1:2) echo explicitly;
  map the reversal against the creation days — most important ANE cosmological
  passage in the prophets.
- 5:1 one-righteous-person search: connect explicitly to Abraham's Sodom intercession
  (Gen 18:23-33) — Jerusalem has fallen below Sodom's standard.
- 6:14 "peace, peace": note the false-prophet formula and its NT echoes (1 Thess 5:3).
- 4:4 heart circumcision: connects to Deut 10:16 and 30:6; Paul develops in Rom 2:28-29.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")


def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


JER = {
    "4": {
        "1": "<p>\"If you will return, O Israel, declares the LORD, return to me\" — the covenant-return call (<em>shuv</em>, H7725) opens the chapter: the same verb used for both physical turning and covenant repentance. The double use (<em>im tashuv... eilai tashuv</em>) is characteristic of Jeremiah's covenant-return rhetoric: the conditional return to YHWH is always possible, and it requires returning specifically to him, not merely to religious practice. The historical context: Josiah's reform was underway (Jeremiah began prophesying in 627 BCE, Josiah's 13th year, 1:2) — yet Jeremiah sees through the surface reforms to the heart condition that remains unchanged (see 3:10: \"Judah did not return to me with her whole heart, but only in pretense\").</p>",
        "2": "<p>\"Then you shall swear, 'As the LORD lives,' in truth, in justice, and in righteousness; and the nations will pronounce blessings in him and boast in him\" — the three qualities of legitimate oath-swearing: <em>emet</em> (truth/reliability), <em>mishpat</em> (justice/right judgment), <em>tzedaqah</em> (righteousness). The oath \"as the LORD lives\" (<em>chai YHWH</em>) was the standard Israelite oath formula, but it was being sworn falsely (5:2: \"even when they say 'As the LORD lives,' they are swearing falsely\"). When the oath formula is backed by genuine truth and justice, the nations are drawn to YHWH through Israel's witness — the international mission of the covenant (Gen 12:3; Deut 4:6-8) is realized through Israel's integrity.</p>",
        "3": "<p>\"Break up your untilled ground, and do not sow among thorns\" — the fallow-ground metaphor: <em>nirukhem</em> (uncultivated, hard ground, H5215) is field that has not been broken for planting. The agricultural image is standard in ANE covenant and wisdom texts: Hos 10:12 uses the same image (\"sow for yourselves righteousness, reap loyal love; break up your untilled ground, for it is time to seek the LORD\"). Sowing among thorns produces crop failure — the thorns choke the seed. Jesus's parable of the sower (Mark 4:7,18-19) employs the same imagery: the thorns represent the cares of the world that choke the word. Jeremiah's audience is doing the religious equivalent: going through the motions of covenant-practice on heart-soil that remains hard and thorn-choked.</p>",
        "4": "<p>\"Circumcise yourselves to the LORD, and remove the foreskins of your hearts, you men of Judah and inhabitants of Jerusalem\" — the heart-circumcision demand: this is the second of three Deuteronomy-to-Jeremiah bridge passages (Deut 10:16: \"circumcise the foreskin of your heart\"; Deut 30:6: \"YHWH your God will circumcise your heart and the heart of your offspring\"). Jeremiah issues the command that Deuteronomy 10 already issued; but Deuteronomy 30 prophesied that YHWH himself would perform the operation. Paul's use in Romans 2:28-29 makes the theological point explicit: \"A Jew is one inwardly, and circumcision is a matter of the heart, by the Spirit, not by the letter\" — the outward rite without the inward reality is meaningless. The threat (\"lest my wrath go forth like fire\") grounds the urgency.</p>",
        "5": "<p>\"Announce it in Judah, proclaim it in Jerusalem; sound the trumpet throughout the land and shout: gather together and go into the fortified cities\" — the military-alarm sequence: trumpet (<em>shofar</em>), proclamation, and evacuation to fortified cities. This is the standard ancient warning protocol for an invading army: the rural population abandons fields and villages to shelter behind city walls. The same protocol appears in 6:1 (flee to fortified cities, trumpet at Tekoa, smoke signal at Beth-hakkerem). The shift from covenant-return rhetoric (vv1-4) to military alarm (vv5-6) is abrupt and jarring — the repentance call and the judgment announcement are simultaneous, because the judgment is already set in motion.</p>",
        "6": "<p>\"Raise the signal flag toward Zion; flee to safety, do not delay; for I am bringing disaster from the north — a great calamity\" — the Foe from the North: <em>ra'ah mitzafon</em> (disaster/evil from the north). The north was the traditional direction of military threat for Israel and Judah — the major invasion routes from Assyria and Babylon both approached from the north because the desert between Mesopotamia and Canaan forced armies to follow the Fertile Crescent's northern arc. The signal flag toward Zion is not a beacon of hope but a military warning: the population should converge on Jerusalem's fortress. The identity of the Foe from the North is debated: Herodotus (1.105) describes a Scythian incursion through the Near East ca. 627-620 BCE that some scholars connect to Jeremiah's early oracles; after 605 BCE (Nebuchadnezzar's victory at Carchemish), Babylon becomes the obvious referent. The oracles maintain a deliberate ambiguity — the theological meaning (YHWH bringing judgment through a northern empire) applies regardless of which empire.</p>",
        "7": "<p>\"The lion has come out of his thicket, and the destroyer of nations has set out; he has gone forth from his place to make your land a waste\" — the lion metaphor for the Foe from the North: the lion emerges from its forest lair to devastate. In ANE royal iconography, the lion represented the power of destruction — Assyrian kings are depicted hunting lions as a symbol of royal dominance. YHWH here uses the lion-force of the northern empire as his instrument of judgment. The title \"destroyer of nations\" (<em>mashhit goyim</em>) is a term for the Babylonian empire's role in the ancient world — Nebuchadnezzar destroyed not only Jerusalem but also Nineveh, Ashkelon, and other major cities. The \"cities will be laid in ruins, without inhabitant\" describes the depopulation strategy of ancient Near Eastern conquest warfare.</p>",
        "8": "<p>\"Because of this, put on sackcloth, and wail and howl; for the fierce anger of the LORD has not turned away from us\" — the communal mourning response commanded: sackcloth (<em>saq</em>, H8242) was the coarse cloth worn in mourning and penitence throughout the ancient Near East (cf. Gen 37:34; 2 Sam 3:31; 1 Kgs 21:27; Jon 3:5). The prophetic use of mourning-language (\"wail and howl,\" <em>yelilu veheililu</em>) anticipates the professional mourning of the fall — but here it is commanded as a response to prophetic announcement, not as a reaction to actual catastrophe. The community is called to mourn before the disaster falls, in recognition that judgment is already determined.</p>",
        "9": "<p>\"In that day, declares the LORD, the king's courage will fail, along with the courage of the officials; the priests will be appalled, and the prophets will be horrified\" — the four leadership classes (king, officials, priests, prophets) will all experience the same failure of nerve. In ANE honor culture, courage under military threat was the primary virtue of kings and warriors — its failure was the deepest possible shame. The specific inclusion of the priests and prophets alongside civil-military leadership indicates that no institution can provide security when YHWH brings judgment. The false prophets of 6:13-14 (who say \"peace, peace\") will be among those \"horrified\" — their own words turned against them by the reality of the invasion.</p>",
        "10": "<p>\"Then I said, 'Ah, Lord GOD! You have truly deceived this people and Jerusalem, saying, \"You shall have peace,\" when in fact a sword reaches to the throat'\" — Jeremiah's protest against YHWH: the prophet accuses YHWH of deceiving the people by giving them prophets who promised peace. This is one of the most theologically difficult passages in Jeremiah — the prophet places the blame for the false-peace expectation on YHWH himself. The Hebrew <em>nasha</em> (H5377, deceive, beguile) is strong language. Commentators differ: some read it as YHWH permitting the false prophets to speak (as in 1 Kgs 22:22 where YHWH puts a lying spirit in the false prophets); others read it as Jeremiah's emotional protest in the face of the people's false expectations. The confession form (\"Lord GOD\") is typical of prophetic lament (6:11; 14:13; 32:17).</p>",
        "11": "<p>\"At that time it will be said to this people and to Jerusalem: A scorching wind from the bare heights of the wilderness is toward the daughter of my people\" — the <em>sirocco</em> (the hot, dry east wind from the desert) as a metaphor for the Foe from the North: the wind image transitions from the military metaphor (vv5-9) to the meteorological. The \"bare heights\" (<em>shefahim</em>) are the treeless highlands of the desert — the source of the desiccating wind. The phrase \"daughter of my people\" (<em>bat ammi</em>) is Jeremiah's characteristic term of affection mixed with lament for Jerusalem — it appears 11 times in Jeremiah and 5 times in Lamentations, capturing the intimacy combined with announcement of judgment that characterizes Jeremiah's entire prophetic ministry.</p>",
        "12": "<p>\"A wind stronger than these will come at my command; now I will pronounce judgment against them\" — the scorching wind is intensified: not the natural sirocco but something YHWH sends specifically for judgment. The phrase \"at my command\" marks the transition from warning to verdict: YHWH is no longer withholding the formal declaration of judgment but issuing it. The legal metaphor (<em>mishpatim</em>, H4941, judgments/verdicts) frames the judgment announcement as a covenant-lawsuit conclusion — the case has been heard, the evidence presented, and the verdict is now pronounced.</p>",
        "13": "<p>\"Look — he advances like storm clouds; his chariots are like a whirlwind, his horses swifter than eagles. We are doomed, for we are ruined!\" — the theophany imagery applied to the Foe from the North: storm clouds (<em>ananim</em>), whirlwind (<em>supha</em>), eagle-swift horses. The storm-theophany language was used for YHWH's direct appearances (Ezek 1:4; Nah 1:3; Hab 3:8). Here it is applied to the approaching army, signaling that the enemy comes with the force of divine manifestation — the Foe from the North is YHWH's agent coming in something like theophanic power. The eagle-speed comparison appears in both Hab 1:8 (the Babylonians) and Deut 28:49 (the cursing of unfaithful Israel) — another connection between Jeremiah's oracles and the Deuteronomy curse-structure.</p>",
        "14": "<p>\"O Jerusalem, wash the evil from your heart, so that you may be saved. How long will you harbor your wicked schemes?\" — the final repentance call before the extended judgment passage: the washing metaphor (<em>kabsi merah libbech</em>) is the inner/outer distinction Jeremiah consistently makes. External washing (ritual) without inner cleansing (<em>lev</em>, heart) produces nothing. The \"how long\" (<em>ad matai</em>) formula is the prophetic expression of YHWH's patience exhausted — it appears in the Psalms (Ps 13:1,2; 79:5; 80:4) as a lament about suffering; here Jeremiah turns it as YHWH's question to the people about their sin.</p>",
        "15": "<p>\"For a voice proclaims from Dan and announces disaster from Mount Ephraim\" — Dan was the northernmost city of Israel, at the foot of Mount Hermon — the first Israelite city that would be seen by an invader descending from the north. Mount Ephraim is the central hill country of the northern tribes. The warning-network running from Dan south through Ephraim to Jerusalem maps the invasion's path: the foe enters at Dan, passes through Ephraim, and the report reaches Jerusalem. The same north-to-south progression appears in Jer 8:16 (\"the snorting of their horses is heard from Dan\"). This geographic specificity grounds the threat in the actual topography of the land — a military movement through identifiable terrain.</p>",
        "16": "<p>\"Tell the nations, announce concerning Jerusalem: Besiegers are coming from a distant land, raising their battle cry against the cities of Judah\" — the international announcement: the nations are to be told about Jerusalem's judgment (cf. 6:18-19: \"Therefore, you nations, hear; you witnesses, know what has happened among them\"). Jerusalem's fall is an international theological event, not merely a local political disaster. The besiegers' battle cry (<em>kolam qol yitnenu</em>) is the ancient war-shout that demoralized defenders — Philistine battle cries (1 Sam 4:5; 17:52) and Israelite cries (Josh 6:5,16,20) had the same psychological-warfare function.</p>",
        "17": "<p>\"Like guards surrounding a field, so they surround her on every side, because she has rebelled against me, declares the LORD\" — the siege metaphor as encirclement: guards (<em>shomrim</em>) surrounding a field to prevent trespassers also prevent exit. The complete encirclement of Jerusalem is both military tactic and theological symbol — there is no escape from covenant judgment once it falls. The ground for the siege: \"because she has rebelled against me\" (<em>ki oti maratah</em>). The verb <em>marah</em> (H4784, rebel/defy) describes the specific covenant-rebellion that triggers the curse — not mere failure but active defiance.</p>",
        "18": "<p>\"Your conduct and your actions have brought this on you. This is your punishment; how bitter it is! How it has pierced to the heart!\" — the self-caused judgment: the punishment is the direct consequence of the conduct and actions. This is the covenant's structural logic: choosing covenant-breach is choosing the curse's consequences. The bitterness reaches the heart (<em>ad libbech naga</em>) — the judgment penetrates to the very organ Jeremiah has been urging them to cleanse (vv4,14).</p>",
        "19": "<p>\"My anguish, my anguish! I writhe in pain! The chambers of my heart are throbbing; I cannot keep silent, for I have heard the sound of the trumpet, the alarm of battle\" — Jeremiah's lament: the first of the great Jeremianic anguish passages. The prophet hears the war-trumpet of the coming judgment and his body responds: throbbing heart-chambers (<em>qirot libbi homeh li</em>, the walls of my heart are groaning for me), silence impossible. The debate among commentators: is this YHWH speaking (sharing divine pathos over the coming judgment) or Jeremiah speaking (prophetic identification with the coming disaster)? The ambiguity may be deliberate — Jeremiah's prophetic identity involves such deep participation in YHWH's pathos that the two voices become difficult to distinguish.</p>",
        "20": "<p>\"Crash after crash — the whole land is laid waste! In a flash my tents are destroyed, my tent-curtains gone in an instant\" — the rapid-succession destruction: <em>shever al shever</em> (crash upon crash, H7667) is the staccato rhythm of catastrophe. The phrase anticipates the wholesale devastation of the country beyond Jerusalem, not merely the capital's siege. Lamentations 2:13 uses the same <em>shever</em> for the destruction of daughter Zion: the Lamentations poet was formed in the same prophetic tradition as Jeremiah.</p>",
        "21": "<p>\"How long must I see the battle standard and hear the blare of the trumpet?\" — the lament's rhetorical question: the prophet is saturated with war-signals (standard, trumpet) and asks how long the vision of judgment must continue. The battle standard (<em>nes</em>, H5251) was the military rallying-flag; its constant visibility and the trumpet's constant sound represent the sustained prophetic burden of announcing a war that has not yet come but is seen as certain. Jeremiah's ministry spans 40+ years (627-586 BCE) of repeated war-announcements — this question captures the exhausting vocation of a prophet whose warnings are consistently rejected.</p>",
        "22": "<p>\"For my people are foolish — they do not know me; they are stupid children; they have no understanding. They are clever at doing evil; as for doing good, they know nothing\" — YHWH's verdict on Israel's moral inversion: the knowledge of YHWH (<em>da'at YHWH</em>) was the central covenant requirement (Hos 4:1,6; 6:6; Jer 2:8). Its absence is described as foolishness (<em>ewilim</em>, H191), stupidity (<em>benim sikkalim</em>), and lack of understanding. The irony in the final phrase: they are expert at evil (<em>lehara hishkilu</em>) but know nothing of good (<em>ulheitev lo yadau</em>). The inversion of wisdom and foolishness — using intelligence for corruption — is a prophetic commonplace (Isa 5:20-21; Amos 6:1).</p>",
        "23": "<p>\"I looked at the earth and it was formless and void; I looked at the heavens and their light was gone\" — the cosmic-undoing vision begins: the Hebrew <em>tohu vavohu</em> (H8414+H922, formless and void) is the precise phrase of Genesis 1:2 (\"Now the earth was formless and void, and darkness was over the face of the deep\"). Jeremiah sees the Babylonian invasion not as a political event but as a cosmic reversal — the creation is being undone. The sequence of vv23-26 systematically reverses the creation-week: no light (Day 1 reversed), mountains quaking (Day 3 reversed), no birds (Day 5 reversed), no humans (Day 6 reversed). This is the most explicit creation-undoing passage in the Hebrew prophets, using Gen 1's vocabulary to describe judgment as de-creation.</p>",
        "24": "<p>\"I looked at the mountains and they were quaking; all the hills were swaying\" — the upheaval of the land's foundations: in Genesis 1, the land appears on Day 3 when the waters are gathered. Here the land shakes — its solid existence is reversed. Mountains and hills were the symbol of permanence in ANE culture (Ps 125:1-2; Isa 54:10: \"though the mountains be shaken\"). Their quaking under the Babylonian invasion signals that the stability of creation itself is threatened. The quaking mountain theophany (Exod 19:18; Ps 18:7; 68:8; Mic 1:4) associates the earthquake with YHWH's direct presence — the mountains shake because YHWH's judgment is an encounter with divine power, not merely human military force.</p>",
        "25": "<p>\"I looked — there was no human being, and all the birds of the sky had flown away\" — the absence of Day 6 creation (humans) and Day 5 creation (birds): Genesis 1:20-28 created birds and then humans in sequence. Their complete absence in Jeremiah's vision signals that the creation-order has been reversed to before their appearance. The flight of birds from a land indicates environmental catastrophe — birds flee drought, pestilence, and military violence. Archaeological surveys of the region around Jerusalem show a dramatic drop in faunal diversity in the 6th century BCE levels at many sites. The creation imagery is not merely literary — it describes the actual ecological devastation of war and displacement.</p>",
        "26": "<p>\"I looked — the fertile land was a desert; all its cities lay in ruins before the LORD, because of his fierce anger\" — the agricultural reversal: the <em>karmel</em> (H3760, fertile land/garden land — the cultivated agricultural land of Canaan) becomes <em>midbar</em> (H4057, desert/wilderness). This is the Exodus reversal: YHWH brought Israel from <em>midbar</em> into <em>karmel</em>; the judgment returns the land to <em>midbar</em>. The cause is stated: \"before the LORD, because of his fierce anger\" (<em>mippenei YHWH mippenei charon appo</em>). YHWH's anger is the direct agent of the de-creation — the judgment is not the chaos of an absent God but the order-reversal of a present one.</p>",
        "27": "<p>\"For this is what the LORD says: The whole land will be desolate, yet I will not make a complete end\" — the qualified destruction: total desolation but not complete annihilation (<em>velo asseh kalah</em>). This qualifying clause is repeated in 5:10,18 and 30:11 — it is Jeremiah's consistent qualification of the judgment announcements. The destruction is total in scope (all cities, the whole land) but not total in outcome (a remnant survives). This is the theological basis for Jeremiah's restoration oracles in chapters 30-33: the same YHWH who brings this judgment maintains the covenant promise through the remnant.</p>",
        "28": "<p>\"For this the earth will mourn and the heavens above grow dark; for I have spoken, I have decided, and I will not relent or turn back\" — the cosmic mourning: the earth mourning (<em>tieval ha'aretz</em>) and dark heavens (<em>vaqadru hashamayim</em>) are the creation's response to YHWH's judgment. In ANE creation-theology, the land's mourning was a sign of cosmic disorder (cf. Hos 4:3: \"the land mourns, and all who live in it languish\"). YHWH's triple assertion of certainty — \"I have spoken\" (<em>dibarti</em>), \"I have decided\" (<em>zamoti</em>), \"I will not relent\" (<em>velo nichamti</em>) — closes all avenues of reprieve. The judgment has been spoken, decided, and made final.</p>",
        "29": "<p>\"Every city is abandoned; they flee from the noise of horsemen and archers; they hide in thickets and climb up among the rocks\" — the universal civilian flight: the entire population abandons their cities in panic at the sound of enemy horsemen and archers. The thickets and rock crevices used for hiding recall the images from Isa 2:21 (people hiding in caves from YHWH's judgment) and Mic 7:14 (the remnant hiding in the forest). Archaeological surveys of Judahite sites from the 6th century BCE show abandonment levels consistent with rapid, panicked departure.</p>",
        "30": "<p>\"And you, O desolate one — what will you do? Though you clothe yourself in crimson, though you adorn yourself with golden jewelry, though you put antimony on your eyes\" — Daughter Zion as a courtesan who adorns herself to attract lovers (the metaphor of Israel as unfaithful wife/prostitute runs through Jer 2:20-25 and Ezek 16,23). The crimson clothing (<em>shani</em>), golden jewelry (<em>kelay zahav</em>), and antimony eye-paint (<em>pukh</em>, H6320 — the black eye-liner used in the ancient Near East, attested in Egyptian cosmetics and referenced in 2 Kgs 9:30 for Jezebel) are all luxury adornments associated with sexual display. No amount of beauty-enhancement will attract allies who can save Jerusalem from the coming judgment.</p>",
        "31": "<p>\"For I heard a cry like a woman in labor, anguish like a first-time mother — the cry of Daughter Zion, gasping and reaching out her hands: 'Woe is me! I am fainting before killers!'\" — the chapter ends with the labor-pain image for Jerusalem's distress. The first-time-mother (<em>bakorah</em>, H1069 — the first labor is the most severe) intensifies the anguish: this is a pain without prior experience, without the reassurance of having survived it before. The outstretched hands reaching out (<em>peresta kappeha</em>) are the gesture of desperation and surrender. The shout \"woe is me\" (<em>oy na li</em>) is the cry of someone who has already given up. The chapter closes with Jerusalem as a victim, not a penitent — the opportunity for the repentance of vv1-4 has passed.</p>"
    },
    "5": {
        "1": "<p>\"Go up and down the streets of Jerusalem, look around and consider; search through her public squares to see whether you can find a man — anyone who does justice and seeks truth, so that I may forgive her\" — the one-righteous-person search: the direct parallel to Abraham's intercession for Sodom (Gen 18:23-33) where YHWH offered to spare the city for ten righteous. Here the standard has been reduced to one — and the search fails. The verb <em>suru</em> (go about, search systematically, H7751) describes a thorough investigation of the city's streets (<em>chutzot</em>) and squares (<em>rehovot</em>). The failure to find even one person who does justice (<em>oseh mishpat</em>) and seeks truth (<em>mevaqesh emunah</em>) is the formal legal finding that makes forgiveness impossible: the city has fallen below the minimum standard for covenant clemency. It has fallen below Sodom's standard.</p>",
        "2": "<p>\"Even when they say 'As the LORD lives,' they are swearing falsely\" — the false-oath indictment: the standard Israelite oath formula (<em>chai YHWH</em>) has been emptied of content. The covenant formula is retained while the covenant reality (truth, justice, faithfulness) is abandoned. This is the worship-without-substance critique that runs through the prophets: Isa 29:13 (\"this people honors me with their lips but their heart is far from me\"); Amos 5:21-24 (YHWH despises feasts while justice rolls down like water). The false oath is particularly serious because swearing by YHWH's name in falsehood is a direct violation of the third commandment (Exod 20:7; Deut 5:11).</p>",
        "3": "<p>\"LORD, do not your eyes look for faithfulness? You struck them, but they felt nothing; you crushed them, but they refused to take correction; they have made their faces harder than rock; they refuse to return\" — the divine-discipline failure: YHWH struck (<em>hikita</em>) and crushed (<em>kiletam</em>) Israel repeatedly through historical judgments, but there was no corrective response. The hardened face (<em>chizqu faneihem misela</em>) is the metaphor for the obstinacy that makes all discipline futile. Proverbs uses the hardened-face image for the shameless person (21:29: \"a wicked man puts on a bold face\"). The refusal to return (<em>me'enu lashuvah</em>) names exactly the failure of v1's repentance call — Israel has been struck and has refused the shuv-movement toward YHWH.</p>",
        "4": "<p>\"Then I thought, 'These are only the poor; they are ignorant; they do not know the way of the LORD, the requirements of their God'\" — Jeremiah's first explanation for the search's failure: the poor (the common people) may not know the covenant requirements. The <em>dalim</em> (H1800, the poor, the lowly) lack access to the instruction that the educated classes receive. This is a charitable hypothesis — perhaps the leaders know better. The distinction between the knowing elite and the ignorant poor is a common ANE social stratification assumption; Jeremiah momentarily applies it before discovering (v5) that it is false. Both classes have equally refused the covenant.</p>",
        "5": "<p>\"So I went to the leaders and spoke to them, for they surely know the way of the LORD, the requirements of their God. But with one accord they have broken off the yoke and torn off the bonds\" — the disproof of the charitable hypothesis: the leaders (<em>gedolim</em>, H1419 — the great ones, the ruling class) know perfectly well what the covenant requires and have deliberately refused it. The yoke-breaking metaphor (<em>shaveru ol qitzzu mosherot</em>) is from the suzerainty-treaty context: the yoke is the vassal's submission to the suzerain. Breaking the yoke means refusing covenant-submission to YHWH. Jeremiah 2:20 uses the same yoke-breaking metaphor for Israel's historical apostasy: \"long ago you broke off your yoke and tore off your bonds.\" The leaders, who are responsible for covenant instruction, are the worst violators.</p>",
        "6": "<p>\"Therefore a lion from the forest will attack them, a wolf from the desert will ravage them, a leopard will lurk near their cities\" — the three-predator curse: lion (<em>aryeh</em>, H738), wolf (<em>ze'ev</em>, H2061), and leopard (<em>namer</em>, H5246) represent three different predation strategies — the lion attacks openly with power, the wolf raids in packs from the wilderness, the leopard lurks and ambushes near settled areas. Together they cover all attack-vectors. The same three predators appear in Hos 13:7-8 (YHWH himself will be like a lion, leopard, and bear against Israel). The three animals also match the three scales of Judah's apostasy: the leaders (lion-bold), the masses (wolf-pack), and the hidden sinners (leopard-lurkers).</p>",
        "7": "<p>\"How can I forgive you for this? Your children have abandoned me and sworn oaths by gods that are no gods at all. When I fed them to the full, they committed adultery and trooped to the house of a prostitute\" — YHWH's rhetorical question about the impossibility of forgiveness: <em>ech eslach-lach</em> (how shall I forgive you for this?). The grounds given: (1) oath-swearing by non-gods; (2) adultery after satiation — the prosperity of the land produced apostasy rather than gratitude. The connection between full feeding and unfaithfulness echoes Deut 6:11-12 (\"eat and be full... take care lest you forget\") and 8:12-14 (\"when you have eaten and are full... your heart will be lifted up and you will forget\"). Satiation produces the spiritual amnesia that produces apostasy.</p>",
        "8": "<p>\"They are like well-fed, lusty stallions — each neighing after another man's wife\" — the stallion metaphor for sexual insatiability: the well-fed horse (<em>susim mezunim</em>, fattened horses, H2109) neigh after each other's mares regardless of ownership. The prophets consistently use marriage and sexual fidelity as the central metaphor for the covenant relationship (Hos 1-3; Ezek 16,23; Jer 2:20-25). The specific choice of the stallion (a symbol of unchecked appetite and raw drive) emphasizes that this is not a failure of knowledge but a failure of will — they know what they want and pursue it regardless of covenant-constraint.</p>",
        "9": "<p>\"Should I not call them to account for these things? declares the LORD. Should I not take vengeance on a nation like this?\" — the divine-accountability refrain: the rhetorical question with the expected answer \"yes\" recurs verbatim at v29 and 9:9, forming a structural bracket around the corruption-indictment sections of Jeremiah 5-9. The combination of <em>paqad</em> (H6485, visit, call to account, punish) and <em>naqam</em> (H5358, take vengeance) establishes that YHWH's response to Israel's covenant-breach is both juridical (calling to account) and retributive (vengeance) — the two aspects of covenant-enforcement that the Deuteronomy curse-structure anticipated.</p>",
        "10": "<p>\"Advance through her vineyards and ravage them, but do not destroy them completely; strip off her branches, for they do not belong to the LORD\" — the pruning metaphor for partial judgment: YHWH commands the invasion to strip the vine without total destruction. The vine was Israel's identity symbol (Ps 80:8-16; Isa 5:1-7; Jer 2:21) — YHWH is the vinedresser, Israel the vine. The qualification \"but do not destroy them completely\" (<em>velo tassu kalah</em>) repeats 4:27's restraint — the judgment is severe but not annihilating. The final clause \"for they do not belong to the LORD\" (<em>ki lo laYHWH hemma</em>) is the bitter assessment: the vine, which was planted by YHWH (2:21: \"I planted you a choice vine\"), has become a vine that does not belong to him.</p>",
        "11": "<p>\"For the house of Israel and the house of Judah have acted completely faithlessly toward me, declares the LORD\" — the comprehensive covenant-breach indictment: both the northern kingdom (Israel) and the southern (Judah) are guilty. By Jeremiah's time, the northern kingdom had already fallen (722 BCE), but Jeremiah addresses both houses — partly as a historical-theological summary and partly because Judah has not learned from Israel's fate (3:6-11: Judah observed Israel's punishment and did not repent). The adverb <em>bagod bagadu bi</em> (acting very treacherously against me) uses the infinitive absolute for maximum emphasis: completely, thoroughly faithless.</p>",
        "12": "<p>\"They have lied about the LORD and said, 'He will do nothing; no disaster will come upon us; we will not face sword or famine'\" — the functional atheism of covenant-breaking Israel: not formal denial of YHWH's existence but denial of his active covenant-enforcement. \"He will do nothing\" (<em>lo ya'aseh</em>) is the attitude that makes the prophetic warning seem absurd — the past has delivered prosperity and peace despite covenant-violation, so why should the future be different? This is the complacency that the prophets consistently attacked (Amos 6:3: \"you put off the evil day\"; Isa 22:13: \"eat and drink, for tomorrow we die\"). The denial of sword and famine — exactly the covenant curses of Deut 28 — shows that the people had mentally disconnected covenant-stipulations from historical consequence.</p>",
        "13": "<p>\"The prophets are nothing but wind; the word of God is not in them. What they threatened will now happen to them\" — the people's dismissal of the true prophets: the prophets (including Jeremiah) are called <em>ruach</em> (H7307, wind/breath) — empty air, substance-less. The people's counter-evaluation is precisely the opposite of the truth: Jeremiah's word is YHWH's fire (v14), while the false prophets' word is wind (Ezek 13:3: \"foolish prophets who follow their own spirit, and have seen nothing\"). The reversal in v13b — \"what they threatened will now happen to them\" — can be read either as YHWH's response (the people's words will come back on them) or as the people's taunt (the doom-prophets will experience the doom they announced).</p>",
        "14": "<p>\"Therefore, this is what the LORD God of Armies says: Because you have spoken like this, I will make my words in your mouth fire, and this people the wood it consumes\" — the prophetic word as fire: YHWH responds to the \"wind\" dismissal by declaring that Jeremiah's words will prove to be fire, not wind. The fire-word metaphor is developed later in 23:29 (\"is not my word like fire?... and like a hammer that breaks the rock in pieces?\"). The title \"LORD God of Armies\" (<em>YHWH Elohei Tzvaot</em>) is a title that emphasizes YHWH's military sovereignty — it appears when YHWH acts in judgment-warfare contexts. Jeremiah himself is the flint from which the fire-word strikes; the people are the combustible material that will be consumed.</p>",
        "15": "<p>\"Listen: I am bringing a nation against you from far away, O house of Israel, declares the LORD. It is a powerful nation, an ancient nation, a nation whose language you do not know, nor can you understand what they say\" — the Foe from the North described: powerful (<em>am ethan</em>, H386, enduring/permanent), ancient (<em>am me'olam</em>), and linguistically incomprehensible to Israel. The language barrier was a significant element of ancient warfare's terror: the conquering army's commands cannot be understood, making resistance and negotiation both impossible. The Assyrian invasions employed exactly this terror — Sennacherib's field commander addressed the people of Jerusalem in Hebrew specifically to bypass this barrier (2 Kgs 18:26-28).</p>",
        "16": "<p>\"Their quivers are like open graves; they are all mighty men\" — the archer imagery: the quiver (<em>ashpato</em>, H827) as an open grave from which death emerges with each arrow drawn. The arrow from a quiver is as certain in its deadly outcome as the grave — and the grave is always open, always receiving. The \"mighty men\" (<em>giborim</em>, H1368 — warriors, fighting men) are all skilled soldiers, not conscripted civilians: Israel will face professional soldiers, not levies.</p>",
        "17": "<p>\"They will devour your harvests and your food — what your sons and daughters depend on for life. They will devour your flocks and your herds; they will devour your vines and your fig trees. They will pulverize with the sword your fortified cities in which you trust\" — the systematic economic destruction: the enemy consumes the entire economic structure. The five objects of consumption (harvest, flocks, herds, vines, fig trees) are the five pillars of Judah's agricultural economy. The final blow: the fortified cities in which Israel trusted will be smashed. The trust in fortified cities is a recurring target of prophetic critique (Isa 22:11; Jer 4:29; Hab 2:9-11) — the physical security-structure replaces trust in YHWH.</p>",
        "18": "<p>\"Yet even in those days, declares the LORD, I will not make a complete end of you\" — the restraining mercy clause repeated (cf. 4:27): at the maximum point of judgment description, YHWH inserts the promise of non-annihilation. The \"even in those days\" (<em>vegam bayamim hahem</em>) acknowledges the severity of what has been described while holding open the covenant-thread. This is the structural basis for Jeremiah's restoration oracles (chs 30-33): because YHWH does not make a complete end, there is a future beyond the Babylonian exile.</p>",
        "19": "<p>\"When they ask, 'Why has the LORD our God done all this to us?' tell them, 'As you abandoned me and served foreign gods in your own land, so you will serve strangers in a land not your own'\" — the covenant-explanation formula (cf. Deut 29:24-25): the nations, and eventually Israel itself, will ask the theodicy question about the catastrophe. The answer is the covenant-breach formula: you served foreign gods in your land; you will serve foreigners in their land. The symmetry is precise: the service (<em>oved</em>) that should have been given to YHWH alone was given to foreign gods; the punishment is service to foreign masters in foreign territory. The Babylonian exile is YHWH's covenant-mirror: what Israel did to YHWH, YHWH does to Israel.</p>",
        "20": "<p>\"Announce this to the house of Jacob; proclaim it in Judah, saying\" — the announcement formula introducing the creation-wisdom passage: the double audience (house of Jacob = the covenant community, Judah = the political entity) receives the cosmic-wisdom indictment of vv21-24. The proclamation formula (<em>hagidu... vehashmi'u</em>) is the herald's introduction, signaling that what follows is a formal divine declaration of public importance.</p>",
        "21": "<p>\"Listen to this, you foolish and senseless people — you have eyes but do not see; you have ears but do not hear\" — the blindness-deafness indictment quoted by Jesus: Isaiah 6:9-10 formulated the classic blindness-deafness verdict on Israel (\"make their hearts dull, their ears heavy, their eyes blind\"); Jeremiah 5:21 applies it again in the pre-exilic period. Jesus quotes the Isaiah version in the parable of the sower (Mark 4:12) and in explaining why he speaks in parables. Paul quotes Deut 29:4 and Isa 29:10 in Romans 11:8. The accusation is not merely perceptual failure but the willful refusal to perceive — the eyes and ears are working; what is missing is the heart's response to what they perceive.</p>",
        "22": "<p>\"Should you not fear me? declares the LORD. Should you not tremble before me? I am the one who set the sand as the boundary for the sea\" — the creation-wisdom argument for covenant-fear: YHWH set the sand as the sea's permanent boundary (<em>chol shamti gvul layam chuqat olam</em>, sand I set as the boundary for the sea, a permanent ordinance). The sand holds back the ocean not by its inherent strength but by YHWH's decree — a constant display of sovereign power that Israel observes daily along the Mediterranean coast. If the sea obeys YHWH's boundary ordinance, why does Israel not obey its covenant ordinances? The implicit argument: creation's elements know their boundaries; covenant-Israel does not know its.</p>",
        "23": "<p>\"But this people has a stubborn, rebellious heart; they have turned away and left\" — the contrast with creation's obedience: the sea stays within its boundary; Israel has a stubborn (<em>sorer</em>, H5637) and rebellious (<em>umorah</em>, H4784) heart. The same root used in the \"rebellious son\" law of Deut 21:18-21 — Israel is the covenant son who has become the unmanageable rebel. The \"turned away and left\" (<em>yisuru vayelechu</em>) mirrors the covenant-departure language of Deut 9:12 (\"they have turned away quickly from the way I commanded\"). The physical picture: the sea that stays within its boundary versus the people who turn and walk away from theirs.</p>",
        "24": "<p>\"They do not even say in their hearts, 'Let us now fear the LORD our God, who gives the autumn and spring rains in season, who assures us of the regular weeks of harvest'\" — the rain-provision argument: YHWH gives both the <em>yoreh</em> (H3138, early rains, autumn rains that begin the agricultural year, October-November) and the <em>malqosh</em> (H4456, late rains, spring rains that swell the grain before harvest, March-April). Israel benefits from this two-season rain pattern every year but does not draw the covenant-fear conclusion: YHWH controls our food supply, therefore we should fear and obey him. The seasonal agricultural rhythm is YHWH's covenant sign of provision — its regularity should produce gratitude and fear, but instead it produces presumption.</p>",
        "25": "<p>\"Your iniquities have diverted these good things, and your sins have kept them from you\" — the covenant-mechanism stated: sin diverts the good things that YHWH's natural provision would otherwise deliver. The drought and agricultural failure that Jeremiah's generation was experiencing (3:3: \"the autumn rains have been withheld; the spring showers have not come\") were the covenant curses of Deut 28:23-24 (bronze sky, iron ground, rain turned to dust) made historically real. The connection between covenant-breach and agricultural failure is not mechanistic magic but YHWH's active covenant-enforcement through the creation systems he governs.</p>",
        "26": "<p>\"For among my people there are wicked men — they lurk like hunters who set traps; they lay snares and catch people\" — the economic exploitation described in hunter-trapper imagery: the wicked (<em>resha'im</em>) are bird-trappers who lie in ambush (<em>yashuru shachim</em>). The comparison of economic exploitation to animal-trapping is unusual in the OT prophets — Amos uses it differently (2:6-7: selling the poor for a pair of sandals) while Jeremiah specifies the predatory technique. The trap-imagery suggests premeditation: they study their victims before acting, lay the trap carefully, and wait for the vulnerable to fall in.</p>",
        "27": "<p>\"As a cage is full of birds, so their houses are full of goods gotten by deceit; that is how they became great and rich\" — the bird-cage metaphor: the trap-laid birds fill a cage; the predatory wealth extracted by exploitation fills the houses of the wicked. \"How they became great and rich\" (<em>shemenu gam ashiru</em>) is bitter irony: their socio-economic advancement is the direct result of their exploitation of the vulnerable. This is the inverse of the covenant's blessing-structure (Deut 28:11-12): covenant-obedience produces wealth through YHWH's blessing; these men produce wealth through covenant-violation at the expense of others.</p>",
        "28": "<p>\"They have grown fat and sleek; they surpass all limits in their evil deeds. They do not defend the rights of the fatherless, so as to make their cause prosper, and they do not uphold the justice of the poor\" — the wealthy-oppressor profile: fat (<em>shamanu</em>, H8080) and sleek (<em>atsemu</em>) describes the well-fed, physically powerful oppressor. The specific failures: not defending the rights of the orphan (<em>din yatom lo danu</em>) and not upholding justice for the poor (<em>mishpat evyonim lo shafetu</em>). These two groups are Deuteronomy's most protected legal categories (Deut 10:18; 14:29; 16:11,14; 24:17,19-21; 27:19). The failure to protect them is the most direct violation of the covenant's social-justice requirements, and it is precisely what prosperity has produced in the leadership class.</p>",
        "29": "<p>\"Should I not call them to account for these things? declares the LORD. Should I not take vengeance on a nation like this?\" — the accountability refrain restated (cf. v9): the rhetorical question brackets the entire corruption-description of vv10-28. The repetition creates a formal legal structure — the charges were laid (v9), the evidence presented (vv10-28), and the verdict restated (v29). The \"nation like this\" (<em>am kazeh</em>) frames Israel as an instance of a type — a nation that has so corrupted its covenant-character that it has become unrecognizable as a covenant-people.</p>",
        "30": "<p>\"A horrible and shocking thing has occurred in the land\" — the <em>horror-desolation formula</em>: <em>shamah venasha'ra niheitah</em> (a horrible/appalling and disgusting thing). The word pair <em>shamah</em> (H8047, desolation/horror) and <em>nasha'rah</em> (H8186, something appalling/disgusting) appears also in Jer 23:14 (concerning the prophets of Jerusalem), Hos 6:10 (concerning the house of Israel), and Jer 18:13 (concerning virgin Israel). The full content of the horrible thing is given in v31 — it is not merely a moral failure but a social conspiracy between corrupt religious leaders and a willing people.</p>",
        "31": "<p>\"The prophets prophesy what is false, the priests exercise authority on their own terms, and my people love it this way. But what will you do when the end comes?\" — the systemic religious conspiracy: three groups are implicated. (1) Prophets who prophesy falsely (<em>hannevi'im nib'u vasheqer</em>); (2) priests who rule by their own authority (<em>vehakohanim yirdu al yadeihem</em>); (3) the people who love it (<em>va'ami ahavu chen</em>). The third element is the most damning: the false-prophets and corrupt-priests could not maintain their positions without a congregation that preferred comfortable lies to uncomfortable truth. Isa 30:10 makes the same point: \"Say to the seers, 'Do not see,' and to the prophets, 'Do not prophesy truth to us; speak smooth things to us'\" — the audience is complicit in its own deception. The closing question \"what will you do when the end comes?\" is the eschatological wake-up call that all three parties ignore.</p>"
    },
    "6": {
        "1": "<p>\"Flee to safety, people of Benjamin — get out of Jerusalem! Sound the trumpet at Tekoa, and raise the smoke signal over Beth-hakkerem; for disaster looks down from the north, and great destruction\" — the specific geography of the warning: Tekoa was a village about 10 miles south of Jerusalem in the Judean highlands (Amos's hometown; 2 Sam 14:2); Beth-hakkerem was another highland beacon-point, possibly identified with Ramat Rachel (about 3 miles south of Jerusalem, where an Iron Age IIB palace-complex has been excavated). Both sites are in the territory of Benjamin, south of Jerusalem — used as signal-stations in the Judean military communication network. The people of Benjamin (Jerusalem's tribal territory) are told to flee from their own capital. The irony: Jerusalem, which should be a refuge, is being evacuated.</p>",
        "2": "<p>\"I will destroy the fair and delicate Daughter Zion\" — the beautiful-woman metaphor for Jerusalem: Daughter Zion (<em>bat Tzion</em>) as a woman of beauty and delicacy (<em>na'ah umefunaqah</em>, graceful and pampered). The same metaphor runs through Lamentations 1-2: \"Daughter Zion\" who has fallen from her previous splendor. In the ancient Near East, city-goddesses (like Inanna/Ishtar) were portrayed as beautiful women; the Lament over the Destruction of Ur depicts the city as a weeping goddess abandoned by her patron deity. Jeremiah's use of the Daughter Zion metaphor taps into this tradition while substituting YHWH-covenant theology for Mesopotamian city-deity theology.</p>",
        "3": "<p>\"Shepherds with their flocks will come to her and pitch their tents around her; each will pasture his portion\" — the pastoral image reversed: shepherds and flocks are normally images of peace and provision (Ps 23; John 10). Here they represent the encamping armies surrounding Jerusalem for siege. The \"pitching of tents\" (<em>taq'u aleha ohalim</em>) is standard military-encampment terminology — ancient armies lived in tent-cities around besieged cities. The pasturing of portions divides the conquest spoils like grazing territories — each commander gets his assigned sector of the besieged city's territory. The pastoral image's inversion underscores the peace-to-judgment transition.</p>",
        "4": "<p>\"Prepare for holy war against her; arise, let us attack at noon. Alas for us, for the day is fading — the evening shadows are growing long\" — the enemy's war-council: the command to sanctify a holy war (<em>qaddeshu aleha milchamah</em>) uses the language of sacred-war preparation found in Joel 3:9 and Mic 3:5. The noon-attack preference reflects ancient military tactics: attacking at maximum visibility when heat-exhausted defenders are least alert. The second half (\"alas for us, for the day is fading\") shows the enemy officers frustrated that the noon opportunity has passed — the siege is taking longer than expected. The evening lengthening shadows create urgency for a night attack (v5): the army is impatient to complete the conquest.</p>",
        "5": "<p>\"Let us rise up and attack by night and demolish her fortified towers\" — the night-attack as backup plan: when the noon opportunity passes, the commanders plan a night assault. Ancient siege warfare often combined daytime catapult and battering-ram operations with nighttime infiltration attempts. The demolition of fortified towers (<em>armenoteha</em>, H759 — palaces or citadels) was the essential objective of ancient siege warfare: the tower was the last refuge of the city's defenders. Archaeological excavations at Lachish (stratum III, ca. 701 BCE) and Tell Beit Mirsim show destruction levels consistent with precisely this kind of assault.</p>",
        "6": "<p>\"For this is what the LORD of Armies says: Cut down trees and build a siege ramp against Jerusalem. This city must be punished; it is filled with oppression\" — the siege ramp construction: the <em>solelah</em> (H5550, siege mound/ramp) was a massive earthwork piled against a city's wall to allow attacking forces to scale or breach it. Archaeologists have found the Assyrian siege ramp at Lachish still in place — the most complete example of an ancient siege ramp in the world. The ramp required enormous quantities of timber for reinforcement and thousands of man-hours of labor. YHWH commands the ramp's construction himself — the siege operation is YHWH's own project against his rebellious city. The reason: \"it is filled with oppression\" (<em>hi ha'ir ha'uqah kulah beqirba</em>, this is the oppressive city; nothing but oppression is within her).</p>",
        "7": "<p>\"As a well keeps pouring out water, so she keeps pouring out wickedness; sounds of violence and devastation are heard in her, before me continually are sickness and wounds\" — the well metaphor for continuous wickedness: a well (<em>bor</em>, H953) produces water without cessation — Jerusalem produces wickedness with the same inexhaustibility. The specific contents: violence (<em>chamas</em>, H2555), devastation (<em>shod</em>, H7701), sickness (<em>choli</em>, H2483), wounds (<em>makkah</em>, H4347). These four terms span the physical, social, and moral dimensions of the city's dysfunction. The phrase \"before me continually\" (<em>lanegdi tamid</em>) establishes that YHWH observes all of it — the wickedness is not hidden from him despite the city's religious facade.</p>",
        "8": "<p>\"Take warning, O Jerusalem, or I will turn away from you; I will make you a ruin, a land where no one lives\" — the penultimate warning before judgment: the threat of YHWH's turning away (<em>pen tiqa nafshi mimech</em>, lest my soul turn from you) is covenant-desertion language — YHWH withdrawing his covenant presence from the city that was chosen as the place for his name to dwell (Deut 12; 1 Kgs 8:29). When YHWH's presence departs, the city becomes a ruin (<em>shamah</em>, uninhabited desolation). Ezekiel 10-11 depicts this departure in visionary form: the glory of YHWH leaving the temple step by step as judgment falls.</p>",
        "9": "<p>\"This is what the LORD of Armies says: Carefully glean the remnant of Israel as a vinedresser gleans a vine; pass your hand over the branches again like one harvesting grapes\" — the gleaning metaphor for thorough judgment: gleaning (<em>olel yeolelelu</em>, H5953) was the agricultural practice of going through a harvested field or vineyard a second and third time to collect what was missed. In the social law (Lev 19:9-10; Deut 24:19-21), gleaning was reserved for the poor — the landowner was forbidden to glean. Here YHWH reverses the gleaning-law: he himself will glean the vineyard thoroughly, taking the remnant rather than leaving it for the vulnerable.</p>",
        "10": "<p>\"To whom shall I speak and give warning so that they will listen? Look, their ears are closed, and they cannot pay attention. Look, the word of the LORD has become an offense to them; they take no pleasure in it\" — Jeremiah's evangelistic despair: the prophet searches for any audience willing to hear. The closed ears (<em>areila ozneihem</em>, uncircumcised ears) mirror the heart-circumcision demand of 4:4 — just as hearts needed circumcision to receive YHWH's covenant, ears needed circumcision to receive YHWH's word. The phrase \"the word of the LORD has become an offense to them\" (<em>cherpah lahem dvar YHWH</em>) shows the inversion: the covenant's most precious communication is experienced as shameful insult. This mirrors Paul's \"foolishness to Gentiles\" and \"stumbling block to Jews\" (1 Cor 1:23) — the gospel is offensive to those whose ears are closed.</p>",
        "11": "<p>\"So I am full of the LORD's fury; I am worn out with holding it in. Pour it out on the children playing in the street and on the young men gathered together; both husband and wife will be taken, the old and the very aged\" — Jeremiah's prophetic saturation: <em>male chamato YHWH</em> (I am full of YHWH's fury). The prophet is the vessel in which YHWH's judgment fills up before being poured out. The exhaustion of restraint (<em>nileti hakil</em>, worn out with holding it in) leads to the comprehensive outpouring: children, young men, husband-wife pairs, and the elderly. No demographic group escapes — the covenant-curse falls on the entire community cross-section. The playing children who are swept up in the judgment are particularly poignant: they are not personally guilty but bear the consequences of their community's covenant-breach.</p>",
        "12": "<p>\"Their houses will be given to others, along with their fields and wives, because I will stretch out my hand against those who live in the land, declares the LORD\" — the property-transfer curse: the property (houses, fields, wives) that defined identity and honor in ancient Israelite land-tenure becomes the property of others — the conquerors. This is the covenant-curse of Deut 28:30-33 (another man will sleep with your betrothed wife; others will devour your produce) being pronounced as imminent. The stretching-out of YHWH's hand (<em>natiti et yadi</em>) is the standard judgment gesture — the same hand that stretched out in the Exodus plagues (Exod 7:5; 9:15) now stretches against Israel.</p>",
        "13": "<p>\"For from the least to the greatest of them, everyone is greedy for dishonest gain; from prophet to priest, everyone acts falsely\" — the comprehensive corruption indictment: the greed for <em>batza</em> (H1215, dishonest gain, unjust profit through exploitation) covers all of society from social bottom to top (<em>miqqetonm ve'ad gedolam</em>), and from religious bottom to top (prophet to priest). The prophet-priest pair are the two most responsible positions for covenant maintenance: the prophet speaks YHWH's word, the priest administers the covenant's ritual and legal procedures. When both practice falsehood, the entire covenant-administration system collapses.</p>",
        "14": "<p>\"They treat the wound of my people as though it were minor, saying, 'Peace, peace,' when there is no peace\" — the \"peace, peace\" formula: <em>shalom shalom ve'ein shalom</em> — one of the most quoted phrases from chapters 4-6. The false prophets and priests diagnosed a terminal wound (<em>shever</em>, H7667, the fracture/break of the people) as minor, and prescribed <em>shalom</em> (peace, wholeness, well-being) when the actual condition was the opposite. The doubled <em>shalom</em> is emphatic: they were insistent and confident in their false diagnosis. This is the canonical example of false prophecy in the OT — applying covenant-blessing language to a covenant-breaking situation. Paul's echo in 1 Thessalonians 5:3 (\"When people say 'Peace and safety,' then sudden destruction will come upon them, like labor pains on a pregnant woman\") uses this same formula for false end-times complacency.</p>",
        "15": "<p>\"Are they ashamed of their detestable conduct? No, they have no shame at all; they do not even know how to blush. Therefore they will fall among the fallen; at the time I punish them, they will stumble, says the LORD\" — the shame-capacity analysis: <em>habosh yevoshu</em> (were they ashamed? they were ashamed?) followed by immediate denial. The ability to feel shame at misconduct is a social-psychological indicator of covenant moral sensitivity. A person who cannot feel shame has passed beyond the point of correction. \"They do not even know how to blush\" (<em>vehikklim lo yadau</em>) indicates that even the physiological shame-response has been eliminated.</p>",
        "16": "<p>\"This is what the LORD says: Stand at the crossroads and look; ask for the ancient paths, ask where the good way is, and walk in it, and you will find rest for your souls\" — the ancient-paths call: <em>shalu lenitevot olam</em> (ask for the ancient paths, H5769 + H5410). The crossroads is the moment of decision — multiple paths diverge. The good way (<em>ezehu derech hatov</em>) is not a new innovation but the ancient covenant-path. This is Jeremiah's conservative-restorative appeal: the solution to Israel's situation is not a new religious program but recovery of the original covenant-path. Jesus quotes this verse's conclusion in Matthew 11:29 (\"you will find rest for your souls\") — he claims to be the ancient path personified: \"I am the way\" (John 14:6). The invitation to rest (<em>margo'a lenafshoteichem</em>) echoes Deut 28:65's exile curse (\"no rest\") in reverse: the covenant-path provides what exile removes.</p>",
        "17": "<p>\"I appointed watchmen over you and said, 'Listen to the sound of the trumpet!' But they said, 'We will not listen'\" — the watchman metaphor: YHWH appointed watchmen (<em>tzofim</em>, H6822 — prophets who stand watch and warn) to sound the trumpet of approaching danger. Ezekiel 3:17 and 33:7 develop the watchman metaphor further, making Ezekiel explicitly responsible for warning Israel. The people's response is flat refusal: \"we will not listen\" (<em>lo nishma</em>). The watchman metaphor grounds the prophets' role in a socially intelligible function — every city had watchmen on its walls who warned of approaching danger. Refusing to heed the watchman's warning was a military capital offense; here it is a covenant-capital offense.</p>",
        "18": "<p>\"Therefore, you nations, hear; you witnesses, know what has happened among them\" — the international testimony: the nations are called as witnesses to Israel's covenant-breach and its consequences (cf. Deut 32:1: \"Listen, heavens; give ear, earth\"; Isa 1:2: \"Hear, heavens! Listen, earth!\"). The nations do not judge Israel — they witness YHWH's judgment. This is the reverse of the Exodus-witness: the Exodus was witnessed by Egypt and the nations as YHWH's redemptive power on Israel's behalf; now the judgment is witnessed by the nations as YHWH's punitive power against his own people.</p>",
        "19": "<p>\"Listen, O earth: I am going to bring disaster on this people — the direct result of their own schemes — because they have not listened to my words and have rejected my law\" — the earth-witness to judgment: the earth (<em>ha'aretz</em>) is called as a witness alongside the nations. The causal chain: their schemes (<em>machshevotehem</em>, H4284, thoughts/plans/devices) → disaster. The disaster is not arbitrary but the direct consequence of their own plans worked through historical process. The rejection of Torah (<em>otati maasu</em>) is the formal covenant-breach that triggers the judgment-curse structure of Deuteronomy 28.</p>",
        "20": "<p>\"What good is it if incense is brought to me from Sheba and fragrant cane from a distant land? Your burnt offerings are not acceptable; your sacrifices do not please me\" — the rejection of luxury worship: incense from Sheba (<em>levona misheva</em>) — southern Arabian frankincense from the Sabaean kingdom (modern Yemen), the most expensive ritual incense in the ancient world; fragrant cane (<em>qaneh hatov</em>, sweet cane) — likely calamus from distant India or Arabia, used in the holy anointing oil (Exod 30:23). The most expensive, exotic ritual ingredients are rejected because they are accompanied by covenant-breach. This is the prophets' consistent teaching: Amos 5:21-24, Isa 1:11-15, Mic 6:6-8, Ps 51:16-17. The worship-apparatus (sacrifices, incense, feasts) cannot substitute for covenant obedience and social justice.</p>",
        "21": "<p>\"Therefore this is what the LORD says: I am going to put obstacles before this people, and they will stumble over them — fathers and sons together; neighbors and friends will perish\" — the stumbling-obstacle judgment: YHWH places <em>mikhsholim</em> (H4383, stumbling blocks, obstacles) before Israel. The stumbling-blocks may be the historical events of the Babylonian invasion — or the covenant curses themselves. The family-structure collapse in the judgment (fathers and sons together stumble; neighbors and friends perish) indicates the social fabric's dissolution. Ezekiel 14:20 describes the same pattern: not even Noah, Daniel, and Job could save their children through personal righteousness when judgment falls on the corporate entity.</p>",
        "22": "<p>\"This is what the LORD says: Look, an army is coming from the northern country, a great nation is being roused from the far ends of the earth\" — the final Foe-from-the-North passage in chapters 4-6: three times the oracle of the northern enemy has appeared (4:6; 5:15; 6:22), building to this climax. The \"great nation roused from the far ends of the earth\" (<em>goy gadol ye'or meyrketei aretz</em>) cannot refer to the Scythians (who were raiders, not a siege-capable army) — by this point in the oracle-collection, Babylon is the most natural referent. The northern-country specification places the origin point at the far end of the Fertile Crescent's arc — Babylon, which approached via the north.</p>",
        "23": "<p>\"They are armed with bow and spear; they are ruthless and without mercy. They sound like the roaring sea as they come riding on horses; they are arrayed like a man in battle against you, Daughter Zion\" — the enemy's weapons profile: bow (<em>qeshet</em>) and spear (<em>chidon</em>) — the two distance-weapons of ancient warfare. The roaring-sea metaphor (<em>kaya'm yehemeh</em>) for the army's sound is a terrifying ANE image of overwhelming, unstoppable force — Isa 5:30 and 17:12 use the same sea-roar for the nations' advance against Jerusalem. The phrase \"against you, Daughter Zion\" personalizes the military advance as an attack on the city-woman figure of v2 — the army encircles the beautiful woman of the chapter's opening.</p>",
        "24": "<p>\"We have heard the report — our hands go limp; distress has seized us, pain like a woman in labor\" — Jerusalem's reaction to the news of the approaching army: the three-stage collapse response — limp hands (paralysis), distress (<em>tzarah</em>, H6869, anguish), labor pains. The labor-pain image for national distress appears at the end of chapter 4 (4:31, Daughter Zion in labor) and recurs here to bracket the entire 4-6 unit. The limp hands (<em>rafu yadenu</em>) are the helplessness response to overwhelming threat — the same image in 2 Sam 17:2 (Ahithophel's plan to attack David when his hands are limp) and Ezek 7:17.</p>",
        "25": "<p>\"Do not go out into the fields or walk along the roads, for the enemy is armed with a sword; terror is on every side\" — the social paralysis of the siege: the countryside is no longer safe for normal movement. The phrase \"terror is on every side\" (<em>magor misaviv</em>) is Jeremiah's signature phrase for his own psychological state (20:10: \"terror is on every side\") and for Jerusalem's condition under siege. It becomes so associated with Jeremiah that Pashhur the priest gives him the nickname \"terror on every side\" (20:3). The phrase encapsulates the claustrophobic fear of siege warfare: no direction is safe.</p>",
        "26": "<p>\"O my dear people, put on sackcloth and roll in the ashes; mourn with bitter weeping as for an only child, because the destroyer will suddenly come upon us\" — the mourning commanded before the event: sackcloth and ashes (<em>saq hittapalshi ve'afer</em>) were the standard mourning-dress of the ancient Near East. The most intense mourning was for an only child (<em>evel yachid</em>) — the loss of the sole heir was the most devastating personal catastrophe because it ended the family line and all its inheritance. The surprise-attack (<em>ki pit'om yavo hashadad aleinu</em>) is the final terror: not a slow siege to prepare for but a sudden devastating assault. The community is commanded to mourn in advance — the only appropriate response to what is certain.</p>",
        "27": "<p>\"I have made you an assayer and a tester among my people, so that you may know and test their conduct\" — the metallurgical metaphor for Jeremiah's prophetic mission: an assayer (<em>bachen</em>, H974) tests the purity of metals by controlled refining. Jeremiah is given this technical role: to test Israel's spiritual purity. The combination of <em>natati-cha mivtzan umivchar</em> (I have made you an assayer and a tester) establishes a dual role — assaying (testing the metal) and broader testing. The prophetic word functions as the heat applied to the metal: under the word's pressure, the dross separates from the pure metal. What Jeremiah discovers in his testing is described in vv28-30.</p>",
        "28": "<p>\"They are all rebellious troublemakers, going about spreading slander; they are bronze and iron — utterly corrupt\" — the assay result: bronze (<em>nechoshet</em>, H5178) and iron (<em>barzel</em>, H1270) are the base metals — worth far less than silver and gold. When the refining reveals bronze and iron rather than silver, the ore is worthless. \"Rebellious troublemakers\" (<em>sarerey sorerim</em>) uses the same root (<em>sar</em>) as the \"rebellious\" charge of v23 (stubbornly rebellious heart). \"Spreading slander\" (<em>holeche rakhil</em>) is the social offense of tale-bearing that destroys community trust (Lev 19:16; Prov 11:13; 20:19). The entire people has revealed itself through the prophetic assay to be base metal — not merely impure silver but the wrong metal entirely.</p>",
        "29": "<p>\"The bellows blow fiercely; the lead is consumed in the flames; the smelter smelts in vain — the wicked are not drawn off\" — the failed refining process: lead was used in ancient smelting as a flux to bind with and remove impurities (argentiferous lead ores were processed to separate silver). When the smelting process fails to produce pure metal, the lead is consumed in vain — the fuel, the flux, and the labor are wasted. The process fails because there is no silver to extract from the ore. This is the metallurgical statement that Jerusalem is unsalvageable through the normal covenant-discipline and prophetic-warning process: no matter how fierce the heat of judgment, the pure silver (the righteous remnant sought in 5:1) is not there to be separated.</p>",
        "30": "<p>\"They will be called rejected silver, for the LORD has rejected them\" — the final verdict: <em>kesef nimaas</em> (rejected silver) — the ore that fails the assay test and is discarded. The prophetic mission of chapters 4-6 ends with this metallurgical verdict: the refining process has been attempted; the prophets have warned; the people have refused; YHWH has found the ore to be base metal and rejected it. The word <em>ma'as</em> (H3988, reject, despise) is the covenant-rejection verb — YHWH's use of it against Israel is the mirror of Israel's rejection of YHWH (5:19: \"as you abandoned me... so you will serve foreigners\"). The chapter that began with the alarm-call to flee to safety ends with the divine verdict of rejection — the most comprehensive and irrevocable judgment in Jeremiah's opening oracles.</p>"
    }
}


def main():
    existing = load_comm("mkt-context", "jeremiah")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, JER)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-context", "jeremiah", existing)
    print(f"Jeremiah mkt-context: {after} verse entries total (+{after - before} new)")
    for ch in ["4", "5", "6"]:
        total = {"4": 31, "5": 31, "6": 30}[ch]
        present = len(existing.get(ch, {}))
        missing = [str(i) for i in range(1, total + 1) if str(i) not in existing.get(ch, {})]
        print(f"  Ch {ch}: {present}/{total} — missing: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
